"use client"

import * as React from "react"
import {
  IconRefresh,
  IconMapPin,
  IconClock,
  IconUsers,
  IconPlaneDeparture,
  IconCircleCheck,
  IconAlertTriangle,
  IconLock,
  IconShieldCheck,
  IconWalk,
  IconChevronRight,
  IconUser,
  IconCircleDot,
  IconFlame,
} from "@tabler/icons-react"
import {
  PageHeader,
  Banner,
  Card,
  CardContent,
  Badge,
  Button,
  Separator,
  FilterChips,
  ListCard,
  Alert,
  AlertTitle,
  AlertDescription,
  MetadataList,
  Icon,
  Drawer,
  DrawerContent,
  DrawerHeader,
  DrawerTitle,
  DrawerDescription,
  DrawerFooter,
  DrawerClose,
} from "@gunjo/ui"

import {
  LOUNGES,
  PRIORITY_SERVICES,
  FLIGHT,
  TRAVELER,
  type Lounge,
  type Crowding,
  type Eligibility,
} from "./data"
import { FacilityRow } from "./facilities"

/* ---------------------------------------------------------------- helpers */

const CROWDING_META: Record<
  Crowding,
  { label: string; variant: "success" | "warning" | "destructive"; glyph: typeof IconCircleDot }
> = {
  empty: { label: "空いています", variant: "success", glyph: IconCircleDot },
  moderate: { label: "やや混雑", variant: "warning", glyph: IconCircleDot },
  busy: { label: "混雑", variant: "destructive", glyph: IconFlame },
}

function CrowdingBadge({ crowding }: { crowding: Crowding }) {
  const m = CROWDING_META[crowding]
  // Map crowding tones onto Badge variants (info/success/warning are the subtle pills).
  const badgeVariant = m.variant === "destructive" ? "warning" : m.variant
  return (
    <Badge
      variant={badgeVariant}
      icon={<m.glyph />}
      className={m.variant === "destructive" ? "border-destructive-border bg-destructive-subtle text-destructive-subtle-foreground" : undefined}
    >
      混雑 {m.label}
    </Badge>
  )
}

const ELIGIBILITY_META: Record<
  Eligibility,
  { label: string; variant: "success" | "info" | "warning" | "secondary"; glyph: typeof IconCircleCheck }
> = {
  eligible: { label: "利用できます", variant: "success", glyph: IconCircleCheck },
  conditional: { label: "条件付き", variant: "info", glyph: IconShieldCheck },
  paid: { label: "有料で利用可", variant: "warning", glyph: IconShieldCheck },
  ineligible: { label: "利用不可", variant: "secondary", glyph: IconLock },
}

function EligibilityBadge({ eligibility }: { eligibility: Eligibility }) {
  const m = ELIGIBILITY_META[eligibility]
  return (
    <Badge variant={m.variant} icon={<m.glyph />}>
      {m.label}
    </Badge>
  )
}

/* ------------------------------------------------------------------ filter */

type FilterKey = "available" | "all" | "inside" | "outside" | "shower" | "meal"

const FILTERS: { value: FilterKey; label: string }[] = [
  { value: "available", label: "利用できるもの" },
  { value: "all", label: "すべて" },
  { value: "inside", label: "制限エリア内" },
  { value: "outside", label: "制限エリア外" },
  { value: "shower", label: "シャワーあり" },
  { value: "meal", label: "食事あり" },
]

function applyFilter(lounge: Lounge, filter: FilterKey): boolean {
  switch (filter) {
    case "all":
      return true
    case "available":
      return lounge.eligibility === "eligible" || lounge.eligibility === "conditional"
    case "inside":
      return lounge.area === "inside"
    case "outside":
      return lounge.area === "outside"
    case "shower":
      return lounge.facilities.includes("shower")
    case "meal":
      return lounge.facilities.includes("meal")
  }
}

/* -------------------------------------------------------------------- page */

export default function AirportLoungePage() {
  const [filter, setFilter] = React.useState<FilterKey>("available")
  const [openId, setOpenId] = React.useState<string | null>(null)

  const visible = React.useMemo(
    () => LOUNGES.filter((l) => applyFilter(l, filter)),
    [filter]
  )

  const selected = React.useMemo(
    () => LOUNGES.find((l) => l.id === openId) ?? null,
    [openId]
  )

  const counts = FILTERS.map((f) => ({
    ...f,
    count: LOUNGES.filter((l) => applyFilter(l, f.value)).length,
  }))

  return (
    <div className="mx-auto flex min-h-full w-full max-w-md flex-col bg-background pb-10">
      <PageHeader
        title="ラウンジ・優先サービス"
        subtitle={`${FLIGHT.flightNo}・${FLIGHT.terminal}`}
        onBack={() => history.back()}
        actions={
          <Button variant="ghost" size="icon" aria-label="最新の状況に更新">
            <IconRefresh className="size-5" aria-hidden="true" />
          </Button>
        }
      />

      {/* ご搭乗便のコンテキスト — boarding countdown */}
      <Banner
        variant="info"
        icon={<IconPlaneDeparture className="size-4" aria-hidden="true" />}
      >
        {`${FLIGHT.gate}番ゲート・搭乗まで約${FLIGHT.boardingInMin}分（${FLIGHT.boardingTime}）`}
      </Banner>

      <div className="flex flex-col gap-5 px-4 pt-4">
        {/* 利用資格（ご搭乗者ステータス） */}
        <section aria-labelledby="status-heading">
          <h2 id="status-heading" className="sr-only">
            あなたの利用資格
          </h2>
          <Card>
            <CardContent className="flex flex-col gap-3 p-4">
              <div className="flex items-start justify-between gap-3">
                <div className="flex min-w-0 items-center gap-2">
                  <span className="flex size-9 shrink-0 items-center justify-center rounded-full bg-muted">
                    <IconUser className="size-5 text-foreground/70" aria-hidden="true" />
                  </span>
                  <div className="min-w-0">
                    <p className="truncate text-sm font-semibold text-foreground">
                      {TRAVELER.name} 様
                    </p>
                    <p className="truncate text-xs text-muted-foreground">
                      {FLIGHT.route}
                    </p>
                  </div>
                </div>
                <Badge variant="default" className="shrink-0">
                  {TRAVELER.memberTier}会員
                </Badge>
              </div>

              <Separator />

              <div className="flex flex-wrap items-center gap-1.5">
                <Badge variant="info" icon={<IconShieldCheck />}>
                  {TRAVELER.cabin}
                </Badge>
                <Badge variant="outline" icon={<IconUsers />}>
                  同伴者 {TRAVELER.companionsAllowed}名まで
                </Badge>
                <Badge variant="outline">{TRAVELER.cardTier}</Badge>
              </div>

              <p className="text-xs leading-relaxed text-muted-foreground">
                上級会員・ビジネスクラスのご利用資格で、本日は
                <span className="font-medium text-foreground"> ANA LOUNGE</span> ・
                <span className="font-medium text-foreground"> ANA SUITE LOUNGE</span>{" "}
                をご利用いただけます。
              </p>
            </CardContent>
          </Card>
        </section>

        {/* 絞り込み */}
        <section aria-labelledby="filter-heading">
          <h2 id="filter-heading" className="mb-2 text-sm font-semibold text-foreground">
            ラウンジ一覧
          </h2>
          <FilterChips
            aria-label="ラウンジの絞り込み"
            value={filter}
            onValueChange={(v) => setFilter(v as FilterKey)}
            items={counts.map((f) => ({
              value: f.value,
              label: f.label,
              count: f.count,
            }))}
          />
        </section>

        {/* ラウンジ一覧 */}
        <section aria-label="ラウンジの一覧">
          {visible.length === 0 ? (
            <Alert>
              <IconAlertTriangle className="size-4" aria-hidden="true" />
              <AlertTitle as="p">該当するラウンジがありません</AlertTitle>
              <AlertDescription>絞り込み条件を変更してください。</AlertDescription>
            </Alert>
          ) : (
            <ul className="flex flex-col gap-2.5">
              {visible.map((lounge) => (
                <li key={lounge.id}>
                  <ListCard
                    onSelect={() => setOpenId(lounge.id)}
                    severity={
                      lounge.eligibility === "eligible"
                        ? "success"
                        : lounge.eligibility === "ineligible"
                          ? "neutral"
                          : "info"
                    }
                    leading={
                      <span
                        className="flex size-10 shrink-0 items-center justify-center rounded-md bg-muted text-foreground/70"
                        aria-hidden="true"
                      >
                        <IconMapPin className="size-5" />
                      </span>
                    }
                    title={
                      <span className="flex items-center gap-2">
                        <span className="truncate">{lounge.name}</span>
                      </span>
                    }
                    description={
                      <span className="flex items-center gap-1 text-xs text-muted-foreground">
                        <IconMapPin className="size-3.5 shrink-0" aria-hidden="true" />
                        {lounge.locationDetail}
                        <span aria-hidden="true">・</span>
                        {lounge.area === "inside" ? "制限エリア内" : "制限エリア外"}
                      </span>
                    }
                    tags={
                      <>
                        <EligibilityBadge eligibility={lounge.eligibility} />
                        <CrowdingBadge crowding={lounge.crowding} />
                        <span className="inline-flex items-center gap-1 text-xs text-muted-foreground">
                          <IconClock className="size-3.5" aria-hidden="true" />
                          {lounge.hours}
                        </span>
                      </>
                    }
                  />
                </li>
              ))}
            </ul>
          )}
        </section>

        {/* 優先サービス */}
        <section aria-labelledby="priority-heading">
          <h2
            id="priority-heading"
            className="mb-2 text-sm font-semibold text-foreground"
          >
            本日の優先サービス
          </h2>
          <ul className="flex flex-col gap-2.5">
            {PRIORITY_SERVICES.map((svc) => (
              <li key={svc.id}>
                <ListCard
                  leading={
                    <span
                      className={`flex size-9 shrink-0 items-center justify-center rounded-full ${
                        svc.available
                          ? "bg-success-subtle text-success-strong"
                          : "bg-muted text-muted-foreground"
                      }`}
                      aria-hidden="true"
                    >
                      {svc.available ? (
                        <IconCircleCheck className="size-5" />
                      ) : (
                        <IconLock className="size-5" />
                      )}
                    </span>
                  }
                  title={svc.title}
                  description={svc.detail}
                  status={
                    svc.available ? (
                      <Badge variant="success" icon={<IconCircleCheck />}>
                        ご利用可
                      </Badge>
                    ) : (
                      <Badge variant="secondary">対象外</Badge>
                    )
                  }
                  trailing={null}
                />
              </li>
            ))}
          </ul>
        </section>
      </div>

      {/* ラウンジ詳細 — bottom sheet */}
      <Drawer open={openId !== null} onOpenChange={(o) => !o && setOpenId(null)}>
        <DrawerContent side="bottom" className="max-h-[88vh]">
          {selected && <LoungeDetail lounge={selected} />}
        </DrawerContent>
      </Drawer>
    </div>
  )
}

/* ----------------------------------------------------------- detail sheet */

function LoungeDetail({ lounge }: { lounge: Lounge }) {
  const elig = ELIGIBILITY_META[lounge.eligibility]
  return (
    <div className="flex min-h-0 flex-col">
      <DrawerHeader className="text-left">
        <div className="flex flex-wrap items-center gap-1.5">
          <EligibilityBadge eligibility={lounge.eligibility} />
          <CrowdingBadge crowding={lounge.crowding} />
        </div>
        <DrawerTitle className="mt-1 text-lg">{lounge.name}</DrawerTitle>
        <DrawerDescription>
          {lounge.operator}・{lounge.terminal}
        </DrawerDescription>
      </DrawerHeader>

      <div className="min-h-0 flex-1 overflow-y-auto px-4 pb-2">
        {/* あなたの場合 */}
        {lounge.note && (
          <Alert
            variant={
              lounge.eligibility === "ineligible"
                ? "warning"
                : lounge.eligibility === "eligible"
                  ? "success"
                  : "info"
            }
            className="mb-4"
          >
            <elig.glyph className="size-4" aria-hidden="true" />
            <AlertTitle as="p">あなたの場合</AlertTitle>
            <AlertDescription>{lounge.note}</AlertDescription>
          </Alert>
        )}

        {/* 概要メタ */}
        <MetadataList
          className="mb-4"
          items={[
            {
              label: "場所",
              value: lounge.locationDetail,
              description: lounge.area === "inside" ? "制限エリア内（保安検査後）" : "制限エリア外（保安検査前）",
              icon: <IconMapPin className="size-4" aria-hidden="true" />,
            },
            {
              label: "営業時間",
              value: lounge.hours,
              icon: <IconClock className="size-4" aria-hidden="true" />,
            },
            {
              label: "同伴者",
              value: lounge.companions,
              icon: <IconUsers className="size-4" aria-hidden="true" />,
            },
          ]}
        />

        {/* ご利用条件 */}
        <h3 className="mb-1.5 flex items-center gap-1.5 text-sm font-semibold text-foreground">
          <IconShieldCheck className="size-4 text-foreground/70" aria-hidden="true" />
          ご利用条件
        </h3>
        <ul className="mb-4 flex flex-col gap-1">
          {lounge.conditions.map((c, i) => (
            <li key={i} className="flex items-start gap-2 text-sm text-muted-foreground">
              <Icon icon={IconChevronRight} size="sm" className="mt-0.5 text-foreground/40" />
              <span>{c}</span>
            </li>
          ))}
        </ul>

        {/* 設備 */}
        <h3 className="mb-1.5 text-sm font-semibold text-foreground">設備</h3>
        <FacilityRow facilities={lounge.facilities} className="mb-4" />

        {/* 行き方 */}
        <h3 className="mb-1.5 flex items-center gap-1.5 text-sm font-semibold text-foreground">
          <IconWalk className="size-4 text-foreground/70" aria-hidden="true" />
          行き方
        </h3>
        <p className="text-sm leading-relaxed text-muted-foreground">
          {lounge.directions}
        </p>
      </div>

      <DrawerFooter className="flex-row gap-2">
        <Button
          variant="primary"
          size="lg"
          className="flex-1"
          disabled={lounge.eligibility === "ineligible"}
        >
          {lounge.eligibility === "ineligible" ? "ご利用いただけません" : "ここへの行き方を見る"}
        </Button>
        <DrawerClose asChild>
          <Button variant="outline" size="lg">
            閉じる
          </Button>
        </DrawerClose>
      </DrawerFooter>
    </div>
  )
}

import {
  IconBath,
  IconToolsKitchen2,
  IconGlassFull,
  IconWifi,
  IconDeviceLaptop,
  IconSmoking,
} from "@tabler/icons-react"
import { Icon } from "@gunjo/ui"
import type { ComponentProps } from "react"
import type { FacilityKey } from "./data"

// The kit's <Icon icon=... /> accepts a Tabler glyph; mirror its expected prop type.
type Glyph = ComponentProps<typeof Icon>["icon"]

export const FACILITY_META: Record<
  FacilityKey,
  { label: string; glyph: Glyph }
> = {
  shower: { label: "シャワー", glyph: IconBath },
  meal: { label: "食事", glyph: IconToolsKitchen2 },
  alcohol: { label: "お酒", glyph: IconGlassFull },
  wifi: { label: "Wi-Fi", glyph: IconWifi },
  work: { label: "仕事スペース", glyph: IconDeviceLaptop },
  smoking: { label: "喫煙室", glyph: IconSmoking },
}

/** Compact facility icon row for a lounge card. Each icon carries an accessible label. */
export function FacilityRow({
  facilities,
  className,
}: {
  facilities: FacilityKey[]
  className?: string
}) {
  return (
    <ul
      className={`flex flex-wrap items-center gap-x-3 gap-y-1 ${className ?? ""}`}
      aria-label="設備"
    >
      {facilities.map((key) => {
        const { label, glyph } = FACILITY_META[key]
        return (
          <li
            key={key}
            className="inline-flex items-center gap-1 text-xs text-muted-foreground"
          >
            <Icon icon={glyph} size="sm" label={label} className="text-foreground/70" />
            <span>{label}</span>
          </li>
        )
      })}
    </ul>
  )
}
